export const sessionBrowserCss = () => `
.session-browser .vfr-page{max-width:1560px}.browser-hero{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:12px;align-items:end}.browser-kicker{margin:0 0 4px;color:var(--v-text-muted);font-size:10px;letter-spacing:.08em;text-transform:uppercase}.browser-subtitle{max-width:760px;margin:6px 0 0;color:var(--v-text-secondary);line-height:1.45}.summary-row{display:flex;gap:5px;flex-wrap:wrap;justify-content:flex-end}.controls{display:grid;gap:7px;margin-top:0}.control-line{display:flex;gap:6px;align-items:center;flex-wrap:wrap}.control-line input,.control-line select{min-height:31px;padding:5px 7px;border:1px solid var(--v-border-default);border-radius:0;background:var(--v-bg-root);color:var(--v-text-primary);font:inherit}.control-line input{min-width:min(360px,100%);flex:1}.filter-button,.clear-button,.show-more,.open{min-height:29px;padding:4px 8px;border:1px solid var(--v-border-default);border-radius:0;background:var(--v-bg-elevated);color:var(--v-text-secondary);font:inherit;font-size:10px;cursor:pointer}.filter-button.active{border-color:var(--v-border-strong);background:var(--v-bg-selected);color:var(--v-text-primary)}.clear-button{font-weight:700}.clear-button:disabled{color:var(--v-disabled);cursor:default}.result-count{margin-left:auto;color:var(--v-text-muted);font-size:10px}.active-summary,.snapshot-note{color:var(--v-text-muted);font-size:10px}.snapshot-note{margin:0}.browser-layout{display:grid;grid-template-columns:minmax(0,1fr) minmax(280px,340px);gap:10px;align-items:start}.session-table{display:grid;gap:6px;min-width:0}.session-group{display:grid;gap:6px}.session-group-header{padding:8px;border:1px solid var(--v-border-subtle);border-radius:0;background:var(--v-bg-elevated)}.session-group-header h2{margin:0;font-size:11px}.session-group-header p{margin:3px 0 0}.session-group-path{margin-top:4px;color:var(--v-text-muted);font-size:9px;overflow-wrap:anywhere}.session-row{display:grid;grid-template-columns:minmax(0,1fr) auto;gap:10px;align-items:center;width:100%;min-width:0;padding:9px;border:1px solid var(--v-border-subtle);border-radius:0;background:var(--v-bg-panel);color:inherit;text-align:left;font:inherit;cursor:pointer}.session-row>*{min-width:0}.session-row:hover,.session-row.selected{border-color:var(--v-border-strong);background:var(--v-bg-selected)}.session-row-main{display:grid;gap:5px;min-width:0}.session-row-kicker,.session-row-meta{display:flex;gap:5px 10px;align-items:center;flex-wrap:wrap}.session-row-title{margin:0;color:var(--v-text-primary);font-size:12px;font-weight:700;line-height:1.3;overflow-wrap:anywhere}.session-row-failure{overflow:hidden;color:var(--v-warning);font-size:10px;line-height:1.35;text-overflow:ellipsis;white-space:nowrap}.session-row-meta{display:grid;grid-template-columns:minmax(92px,112px) minmax(158px,176px) minmax(72px,84px) repeat(3,minmax(64px,1fr));color:var(--v-text-muted);font-size:9px;line-height:1.35}.session-row-source{overflow:hidden;color:var(--v-text-muted);font-size:9px;text-overflow:ellipsis;white-space:nowrap}.session-row-action{align-self:center;white-space:nowrap}.provider-badge,.outcome-pill{display:inline-flex;align-items:center;width:max-content;max-width:100%;min-height:20px;padding:2px 5px;border:1px solid var(--v-border-default);border-radius:0;background:var(--v-bg-elevated);color:var(--v-text-secondary);font-size:9px;font-weight:650;text-transform:uppercase}.outcome-pill.error{border-color:var(--v-danger-border);color:var(--v-danger)}.outcome-pill.success{border-color:var(--v-border-strong);color:var(--v-text-primary)}.open{display:inline-flex;align-items:center;justify-content:center;color:var(--v-text-primary);text-decoration:none}.preview-panel{position:sticky;top:88px;min-width:0}.preview-body{display:grid;gap:9px}.preview-title{color:var(--v-text-primary);font-size:13px;font-weight:700;line-height:1.2;overflow-wrap:anywhere}.preview-stats{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:1px;border:1px solid var(--v-border-subtle);background:var(--v-border-subtle)}.preview-stat-value,.preview-stat-label{display:block}.preview-stat-label,.preview-meta-label{margin-top:3px;color:var(--v-text-muted);font-size:9px}.preview-meta-value,.session-source{overflow-wrap:anywhere;word-break:break-word}.muted{color:var(--v-text-muted);overflow-wrap:anywhere}.file-list{margin:0;padding-left:18px;color:var(--v-text-secondary);font-size:10px}.copy-command{display:block}.empty-filter{display:none}.empty-filter.show{display:block}.pager{display:flex;justify-content:space-between;gap:8px;align-items:center;padding:3px;color:var(--v-text-muted);font-size:9px}.show-more[hidden]{display:none}
@media(max-width:1280px){.browser-layout{grid-template-columns:1fr}.preview-panel{position:static;order:2}.session-row-meta{grid-template-columns:repeat(3,minmax(0,1fr))}}
@media(max-width:900px){.browser-hero{grid-template-columns:1fr}.summary-row{justify-content:flex-start}.result-count{margin-left:0}}
@media(max-width:760px){.session-row{grid-template-columns:1fr}.session-row-action{width:100%}.preview-panel{display:none}.control-line input{min-width:100%}.session-row-meta{grid-template-columns:repeat(2,minmax(0,1fr))}}
`;
